module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
);

localparam GREEN_TIME = 60;
localparam YELLOW_TIME = 5;
localparam RED_TIME = 10;

reg [5:0] state;
reg [5:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= 0;
        count <= 0;
        red <= 0;
        yellow <= 0;
        green <= 1;
    end else begin
        case (state)
            0: begin // Green
                if (count == GREEN_TIME - 1) begin
                    state <= 1; // Transition to Yellow
                    count <= 0;
                end else begin
                    count <= count + 1;
                end
                red <= 0;
                yellow <= 0;
                green <= 1;
            end
            1: begin // Yellow
                if (count == YELLOW_TIME - 1) begin
                    state <= 2; // Transition to Red
                    count <= 0;
                end else begin
                    count <= count + 1;
                end
                red <= 0;
                yellow <= 1;
                green <= 0;
            end
            2: begin // Red
                if (count == RED_TIME - 1) begin
                    state <= 0; // Transition to Green
                    count <= 0;
                end else begin
                    count <= count + 1;
                end
                red <= 1;
                yellow <= 0;
                green <= 0;
            end
            default: begin
                state <= 0;
                count <= 0;
                red <= 0;
                yellow <= 0;
                green <= 1;
            end
        endcase

        if (pass_request && count > 10) begin
            state <= 0; // Reset to Green if pedestrian button is pressed and green time is greater than 10 clocks
            count <= 0;
        end
    end
end

endmodule
